package markets

import (
	"context"
	"time"

	positionsmath "socialpredict/internal/domain/math/positions"
	users "socialpredict/internal/domain/users"
	"socialpredict/models"
)

const (
	MaxQuestionTitleLength = 160
	MaxDescriptionLength   = 2000
	MaxLabelLength         = 20
	MinLabelLength         = 1
)

// Clock provides time functionality for testability.
type Clock interface {
	Now() time.Time
}

type serviceClock struct{}

func (serviceClock) Now() time.Time { return time.Now() }

// MarketReadRepository exposes market reads.
type MarketReadRepository interface {
	GetByID(ctx context.Context, id int64) (*Market, error)
	List(ctx context.Context, filters ListFilters) ([]*Market, error)
	ListByStatus(ctx context.Context, status string, p Page) ([]*Market, error)
	Search(ctx context.Context, query string, filters SearchFilters) ([]*Market, error)
	GetPublicMarket(ctx context.Context, marketID int64) (*PublicMarket, error)
}

// MarketWriteRepository exposes market writes and maintenance operations.
type MarketWriteRepository interface {
	Create(ctx context.Context, market *Market) error
	UpdateLabels(ctx context.Context, id int64, yesLabel, noLabel string) error
	Delete(ctx context.Context, id int64) error
	ResolveMarket(ctx context.Context, id int64, resolution string) error
}

// MarketPositionRepository exposes position-related queries.
type MarketPositionRepository interface {
	GetUserPosition(ctx context.Context, marketID int64, username string) (*UserPosition, error)
	ListMarketPositions(ctx context.Context, marketID int64) (MarketPositions, error)
	CalculatePayoutPositions(ctx context.Context, marketID int64) ([]*PayoutPosition, error)
}

// MarketBetRepository exposes bet history queries.
type MarketBetRepository interface {
	ListBetsForMarket(ctx context.Context, marketID int64) ([]*Bet, error)
}

// Repository defines the interface for market data access.
type Repository interface {
	MarketReadRepository
	MarketWriteRepository
	MarketPositionRepository
	MarketBetRepository
}

// CreatorSummary captures lightweight information about a market creator.
type CreatorSummary struct {
	Username      string
	DisplayName   string
	PersonalEmoji string
}

// ProbabilityPoint records a market probability at a specific moment.
type ProbabilityPoint struct {
	Probability float64
	Timestamp   time.Time
}

// UserService defines the interface for user-related operations.
type UserService interface {
	ValidateUserExists(ctx context.Context, username string) error
	ValidateUserBalance(ctx context.Context, username string, requiredAmount int64, maxDebt int64) error
	DeductBalance(ctx context.Context, username string, amount int64) error
	ApplyTransaction(ctx context.Context, username string, amount int64, transactionType string) error
	GetPublicUser(ctx context.Context, username string) (*users.PublicUser, error)
}

// Config holds configuration for the markets service.
type Config struct {
	MinimumFutureHours float64
	CreateMarketCost   int64
	MaximumDebtAllowed int64
}

// CreationPolicy governs validation and construction of markets.
type CreationPolicy interface {
	ValidateCreateRequest(req MarketCreateRequest) error
	ValidateCustomLabels(yesLabel, noLabel string) error
	NormalizeLabels(yesLabel, noLabel string) labelPair
	ValidateResolutionTime(now time.Time, resolution time.Time, minimumFutureHours float64) error
	EnsureCreateMarketBalance(ctx context.Context, users UserService, creatorUsername string, cost int64, maxDebt int64) error
	BuildMarketEntity(now time.Time, req MarketCreateRequest, creatorUsername string, labels labelPair) *Market
}

// ResolutionPolicy encapsulates resolution rules and post-resolution actions.
type ResolutionPolicy interface {
	NormalizeResolution(resolution string) (string, error)
	ValidateResolutionRequest(market *Market, username string) error
	Resolve(ctx context.Context, repo ResolutionRepository, userService UserService, marketID int64, outcome string) error
}

// ProbabilityChange represents a change in market probability at a timestamp.
type ProbabilityChange struct {
	Probability float64
	Timestamp   time.Time
}

// ProbabilityEngine provides probability calculations and projections.
type ProbabilityEngine interface {
	Calculate(createdAt time.Time, bets []models.Bet) []ProbabilityChange
	Project(createdAt time.Time, bets []models.Bet, newBet models.Bet) ProbabilityProjection
}

// ProbabilityValidator validates projection requests and market eligibility.
type ProbabilityValidator interface {
	ValidateRequest(req ProbabilityProjectionRequest) error
	ValidateMarket(market *Market, now time.Time) error
}

// SearchPolicy encapsulates search query validation and fallback logic.
type SearchPolicy interface {
	ValidateQuery(query string) error
	NormalizeFilters(filters SearchFilters) SearchFilters
	ShouldFetchFallback(primary []*Market, status string) bool
	NewSearchResults(query string, status string, primary []*Market) *SearchResults
	BuildFallbackFilters(primary SearchFilters) SearchFilters
	SelectFallback(primary []*Market, all []*Market, limit int) []*Market
}

// MetricsCalculator computes volume and dust metrics.
type MetricsCalculator interface {
	Volume(bets []models.Bet) int64
	VolumeWithDust(bets []models.Bet) int64
	Dust(bets []models.Bet) int64
}

// LeaderboardCalculator computes leaderboard standings.
type LeaderboardCalculator interface {
	Calculate(snapshot positionsmath.MarketSnapshot, bets []models.Bet) ([]positionsmath.UserProfitability, error)
}

// StatusPolicy validates status filters and pagination rules.
type StatusPolicy interface {
	ValidateStatus(status string) error
	NormalizePage(p Page, defaultLimit, maxLimit int) Page
}

// ListFilters represents filters for listing markets.
type ListFilters struct {
	Status    string
	CreatedBy string
	Limit     int
	Offset    int
}

// SearchFilters represents filters for searching markets.
type SearchFilters struct {
	Status string
	Limit  int
	Offset int
}

// SearchResults represents the result of a market search with fallback.
type SearchResults struct {
	PrimaryResults  []*Market `json:"primaryResults"`
	FallbackResults []*Market `json:"fallbackResults"`
	Query           string    `json:"query"`
	PrimaryStatus   string    `json:"primaryStatus"`
	PrimaryCount    int       `json:"primaryCount"`
	FallbackCount   int       `json:"fallbackCount"`
	TotalCount      int       `json:"totalCount"`
	FallbackUsed    bool      `json:"fallbackUsed"`
}

// ServiceInterface defines the interface for market service operations.
type ServiceInterface interface {
	CreateMarket(ctx context.Context, req MarketCreateRequest, creatorUsername string) (*Market, error)
	SetCustomLabels(ctx context.Context, marketID int64, yesLabel, noLabel string) error
	GetMarket(ctx context.Context, id int64) (*Market, error)
	ListMarkets(ctx context.Context, filters ListFilters) ([]*Market, error)
	SearchMarkets(ctx context.Context, query string, filters SearchFilters) (*SearchResults, error)
	ResolveMarket(ctx context.Context, marketID int64, resolution string, username string) error
	ListByStatus(ctx context.Context, status string, p Page) ([]*Market, error)
	GetMarketLeaderboard(ctx context.Context, marketID int64, p Page) ([]*LeaderboardRow, error)
	ProjectProbability(ctx context.Context, req ProbabilityProjectionRequest) (*ProbabilityProjection, error)
	GetMarketDetails(ctx context.Context, marketID int64) (*MarketOverview, error)
	GetMarketBets(ctx context.Context, marketID int64) ([]*BetDisplayInfo, error)
	GetMarketPositions(ctx context.Context, marketID int64) (MarketPositions, error)
	GetUserPositionInMarket(ctx context.Context, marketID int64, username string) (*UserPosition, error)
	CalculateMarketVolume(ctx context.Context, marketID int64) (int64, error)
	GetPublicMarket(ctx context.Context, marketID int64) (*PublicMarket, error)
}

// Service implements the core market business logic.
type Service struct {
	repo        Repository
	userService UserService
	clock       Clock
	config      Config

	creationPolicy        CreationPolicy
	resolutionPolicy      ResolutionPolicy
	probabilityEngine     ProbabilityEngine
	probabilityValidator  ProbabilityValidator
	searchPolicy          SearchPolicy
	metricsCalculator     MetricsCalculator
	leaderboardCalculator LeaderboardCalculator
	statusPolicy          StatusPolicy
}

// ServiceOption configures the markets service strategies.
type ServiceOption func(*Service)

func defaultClock() Clock {
	return serviceClock{}
}

func defaultCreationPolicyStrategy(config Config) CreationPolicy {
	return defaultCreationPolicy{config: config}
}

func defaultResolutionPolicyStrategy() ResolutionPolicy {
	return defaultResolutionPolicy{}
}

func defaultProbabilityEngineStrategy() ProbabilityEngine {
	return defaultProbabilityEngine{}
}

func defaultProbabilityValidatorStrategy() ProbabilityValidator {
	return defaultProbabilityValidator{}

package markets

import (
	"context"
	"errors"
	"strings"
	"time"

	dmarkets "socialpredict/internal/domain/markets"
	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/models"

	"gorm.io/gorm"
)

// GormRepository implements the markets domain repository interface using GORM
type GormRepository struct {
	db *gorm.DB
}

// NewGormRepository creates a new GORM-based markets repository
func NewGormRepository(db *gorm.DB) *GormRepository {
	return &GormRepository{db: db}
}

// Create creates a new market in the database
func (r *GormRepository) Create(ctx context.Context, market *dmarkets.Market) error {
	dbMarket := r.domainToModel(market)

	result := r.db.WithContext(ctx).Create(&dbMarket)
	if result.Error != nil {
		return result.Error
	}

	// Update the domain model with the generated ID
	market.ID = dbMarket.ID
	return nil
}

// GetByID retrieves a market by its ID
func (r *GormRepository) GetByID(ctx context.Context, id int64) (*dmarkets.Market, error) {
	var dbMarket models.Market

	err := r.db.WithContext(ctx).First(&dbMarket, id).Error
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, dmarkets.ErrMarketNotFound
		}
		return nil, err
	}

	return r.modelToDomain(&dbMarket), nil
}

// GetPublicMarket retrieves a market with public-facing attributes.
func (r *GormRepository) GetPublicMarket(ctx context.Context, marketID int64) (*dmarkets.PublicMarket, error) {
	var market models.Market
	if err := r.db.WithContext(ctx).First(&market, marketID).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, dmarkets.ErrMarketNotFound
		}
		return nil, err
	}

	return &dmarkets.PublicMarket{
		ID:                      market.ID,
		QuestionTitle:           market.QuestionTitle,
		Description:             market.Description,
		OutcomeType:             market.OutcomeType,
		ResolutionDateTime:      market.ResolutionDateTime,
		FinalResolutionDateTime: market.FinalResolutionDateTime,
		UTCOffset:               market.UTCOffset,
		IsResolved:              market.IsResolved,
		ResolutionResult:        market.ResolutionResult,
		InitialProbability:      market.InitialProbability,
		CreatorUsername:         market.CreatorUsername,
		CreatedAt:               market.CreatedAt,
		YesLabel:                market.YesLabel,
		NoLabel:                 market.NoLabel,
	}, nil
}

// UpdateLabels updates the yes and no labels for a market
func (r *GormRepository) UpdateLabels(ctx context.Context, id int64, yesLabel, noLabel string) error {
	result := r.db.WithContext(ctx).Model(&models.Market{}).
		Where("id = ?", id).
		Updates(map[string]any{
			"yes_label":  yesLabel,
			"no_label":   noLabel,
			"updated_at": time.Now(),
		})

	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dmarkets.ErrMarketNotFound
	}

	return nil
}

// List retrieves markets with the given filters
func (r *GormRepository) List(ctx context.Context, filters dmarkets.ListFilters) ([]*dmarkets.Market, error) {
	query := r.db.WithContext(ctx).Model(&models.Market{})

	query = applyListStatusFilter(query, filters.Status)
	query = applyCreatedByFilter(query, filters.CreatedBy)
	query = applyPagination(query, filters.Limit, filters.Offset)
	query = query.Order("created_at DESC")

	var dbMarkets []models.Market
	if err := query.Find(&dbMarkets).Error; err != nil {
		return nil, err
	}

	return r.mapMarkets(dbMarkets), nil
}

// ListByStatus retrieves markets filtered by status with pagination
func (r *GormRepository) ListByStatus(ctx context.Context, status string, p dmarkets.Page) ([]*dmarkets.Market, error) {
	query := r.db.WithContext(ctx).Model(&models.Market{})

	query = applyStatusByResolution(query, status, time.Now())
	query = applyPagination(query, p.Limit, p.Offset)
	query = query.Order("created_at DESC")

	var dbMarkets []models.Market
	if err := query.Find(&dbMarkets).Error; err != nil {
		return nil, err
	}

	return r.mapMarkets(dbMarkets), nil
}

func applyListStatusFilter(query *gorm.DB, status string) *gorm.DB {
	switch status {
	case "active":
		return query.Where("is_resolved = ?", false)
	case "resolved":
		return query.Where("is_resolved = ?", true)
	default:
		return query
	}
}

func applyCreatedByFilter(query *gorm.DB, createdBy string) *gorm.DB {
	if createdBy == "" {
		return query
	}
	return query.Where("creator_username = ?", createdBy)
}

func applyStatusByResolution(query *gorm.DB, status string, now time.Time) *gorm.DB {
	switch status {
	case "active":
		return query.Where("is_resolved = ? AND resolution_date_time > ?", false, now)
	case "closed":
		return query.Where("is_resolved = ? AND resolution_date_time <= ?", false, now)
	case "resolved":
		return query.Where("is_resolved = ?", true)
	default:
		return query
	}
}

// Search searches for markets by query string
func (r *GormRepository) Search(ctx context.Context, query string, filters dmarkets.SearchFilters) ([]*dmarkets.Market, error) {
	dbQuery := r.db.WithContext(ctx).Model(&models.Market{})

	dbQuery = applySearchTerm(dbQuery, query)
	dbQuery = applyStatusFilter(dbQuery, filters.Status)
	dbQuery = applyPagination(dbQuery, filters.Limit, filters.Offset)
	dbQuery = dbQuery.Order("created_at DESC")

	var dbMarkets []models.Market
	if err := dbQuery.Find(&dbMarkets).Error; err != nil {
		return nil, err
	}

	return r.mapMarkets(dbMarkets), nil
}

func applySearchTerm(dbQuery *gorm.DB, query string) *gorm.DB {
	searchTerm := strings.ToLower(query)
	searchPattern := "%" + searchTerm + "%"
	return dbQuery.Where("(LOWER(question_title) LIKE ? OR LOWER(description) LIKE ?)", searchPattern, searchPattern)
}

func applyStatusFilter(dbQuery *gorm.DB, status string) *gorm.DB {
	if status == "" || status == "all" {
		return dbQuery
	}

	now := time.Now()
	switch status {
	case "active":
		return dbQuery.Where("is_resolved = ? AND resolution_date_time > ?", false, now)
	case "closed":
		return dbQuery.Where("is_resolved = ? AND resolution_date_time <= ?", false, now)
	case "resolved":
		return dbQuery.Where("is_resolved = ?", true)
	default:
		return dbQuery
	}
}

func applyPagination(dbQuery *gorm.DB, limit, offset int) *gorm.DB {
	if limit > 0 {
		dbQuery = dbQuery.Limit(limit)
	}

	if offset > 0 {
		dbQuery = dbQuery.Offset(offset)
	}
	return dbQuery
}

func (r *GormRepository) mapMarkets(dbMarkets []models.Market) []*dmarkets.Market {
	markets := make([]*dmarkets.Market, len(dbMarkets))
	for i, dbMarket := range dbMarkets {
		markets[i] = r.modelToDomain(&dbMarket)
	}
	return markets
}

// GetUserPosition retrieves the aggregated position for a specific user in a market.
func (r *GormRepository) GetUserPosition(ctx context.Context, marketID int64, username string) (*dmarkets.UserPosition, error) {
	snapshot, bets, err := r.loadMarketData(ctx, marketID)
	if err != nil {
		return nil, err
	}

	position, err := positionsmath.CalculateMarketPositionForUser_WPAM_DBPM(snapshot, bets, username)
	if err != nil {
		return nil, err
	}

	return &dmarkets.UserPosition{
		Username:         username,
		MarketID:         marketID,
		YesSharesOwned:   position.YesSharesOwned,
		NoSharesOwned:    position.NoSharesOwned,
		Value:            position.Value,
		TotalSpent:       position.TotalSpent,
		TotalSpentInPlay: position.TotalSpentInPlay,
		IsResolved:       position.IsResolved,
		ResolutionResult: position.ResolutionResult,
	}, nil
}

// ListMarketPositions retrieves aggregated positions for all users in a market.
func (r *GormRepository) ListMarketPositions(ctx context.Context, marketID int64) (dmarkets.MarketPositions, error) {
	snapshot, bets, err := r.loadMarketData(ctx, marketID)
	if err != nil {
		return nil, err
	}

	positions, err := positionsmath.CalculateMarketPositions_WPAM_DBPM(snapshot, bets)

	positions, err := positionsmath.CalculateMarketPositions_WPAM_DBPM(snapshot, bets)
	if err != nil {
		return nil, err
	}

	out := make(dmarkets.MarketPositions, 0, len(positions))
	for _, pos := range positions {
		out = append(out, &dmarkets.UserPosition{
			Username:         pos.Username,
			MarketID:         int64(pos.MarketID),
			YesSharesOwned:   pos.YesSharesOwned,
			NoSharesOwned:    pos.NoSharesOwned,
			Value:            pos.Value,
			TotalSpent:       pos.TotalSpent,
			TotalSpentInPlay: pos.TotalSpentInPlay,
			IsResolved:       pos.IsResolved,
			ResolutionResult: pos.ResolutionResult,
		})
	}
	return out, nil
}

// Delete removes a market from the database
func (r *GormRepository) Delete(ctx context.Context, id int64) error {
	result := r.db.WithContext(ctx).Delete(&models.Market{}, id)
	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dmarkets.ErrMarketNotFound
	}

	return nil
}

// ResolveMarket marks a market as resolved with the given resolution
func (r *GormRepository) ResolveMarket(ctx context.Context, id int64, resolution string) error {
	result := r.db.WithContext(ctx).Model(&models.Market{}).
		Where("id = ?", id).
		Updates(map[string]any{
			"is_resolved":                true,
			"resolution_result":          resolution,
			"final_resolution_date_time": time.Now(),
			"updated_at":                 time.Now(),
		})

	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dmarkets.ErrMarketNotFound
	}

	return nil
}

// ListBetsForMarket returns all bets for the specified market ordered by placement time.
func (r *GormRepository) ListBetsForMarket(ctx context.Context, marketID int64) ([]*dmarkets.Bet, error) {
	var bets []models.Bet
	if err := r.db.WithContext(ctx).
		Where("market_id = ?", marketID).
		Order("placed_at ASC").
		Find(&bets).Error; err != nil {
		return nil, err
	}

	result := make([]*dmarkets.Bet, len(bets))
	for i := range bets {
		result[i] = &dmarkets.Bet{
			ID:        bets[i].ID,
			Username:  bets[i].Username,
			MarketID:  bets[i].MarketID,
			Amount:    bets[i].Amount,
			Outcome:   bets[i].Outcome,
			PlacedAt:  bets[i].PlacedAt,
			CreatedAt: bets[i].CreatedAt,
		}
	}
	return result, nil
}

// CalculatePayoutPositions computes the resolved valuations for a market's participants.
func (r *GormRepository) CalculatePayoutPositions(ctx context.Context, marketID int64) ([]*dmarkets.PayoutPosition, error) {
	snapshot, bets, err := r.loadMarketData(ctx, marketID)
	if err != nil {
		return nil, err
	}

	positions, err := positionsmath.CalculateMarketPositions_WPAM_DBPM(snapshot, bets)
	if err != nil {
		return nil, err
	}

	result := make([]*dmarkets.PayoutPosition, 0, len(positions))
	for _, pos := range positions {
		result = append(result, &dmarkets.PayoutPosition{
			Username: pos.Username,
			Value:    pos.Value,
		})
	}
	return result, nil
}

func (r *GormRepository) loadMarketData(ctx context.Context, marketID int64) (positionsmath.MarketSnapshot, []models.Bet, error) {
	var market models.Market
	if err := r.db.WithContext(ctx).First(&market, marketID).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return positionsmath.MarketSnapshot{}, nil, dmarkets.ErrMarketNotFound
		}
		return positionsmath.MarketSnapshot{}, nil, err
	}

	var bets []models.Bet
	if err := r.db.WithContext(ctx).
		Where("market_id = ?", marketID).
		Order("placed_at ASC").
		Find(&bets).Error; err != nil {
		return positionsmath.MarketSnapshot{}, nil, err
	}

	snapshot := positionsmath.MarketSnapshot{
		ID:               int64(market.ID),
		CreatedAt:        market.CreatedAt,
		IsResolved:       market.IsResolved,
		ResolutionResult: market.ResolutionResult,
	}

	return snapshot, bets, nil
}

// domainToModel converts a domain market to a GORM model
func (r *GormRepository) domainToModel(market *dmarkets.Market) models.Market {
	return models.Market{
		ID:                      market.ID,
		QuestionTitle:           market.QuestionTitle,
		Description:             market.Description,
		OutcomeType:             market.OutcomeType,
		ResolutionDateTime:      market.ResolutionDateTime,
		FinalResolutionDateTime: market.FinalResolutionDateTime,
		ResolutionResult:        market.ResolutionResult,
		CreatorUsername:         market.CreatorUsername,
		YesLabel:                market.YesLabel,
		NoLabel:                 market.NoLabel,
		UTCOffset:               market.UTCOffset,
		IsResolved:              market.Status == "resolved",
		InitialProbability:      market.InitialProbability,
	}
}

// modelToDomain converts a GORM model to a domain market
func (r *GormRepository) modelToDomain(dbMarket *models.Market) *dmarkets.Market {
	status := "active"
	if dbMarket.IsResolved {
		status = "resolved"
	}

	return &dmarkets.Market{
		ID:                      dbMarket.ID,
		QuestionTitle:           dbMarket.QuestionTitle,
		Description:             dbMarket.Description,
		OutcomeType:             dbMarket.OutcomeType,
		ResolutionDateTime:      dbMarket.ResolutionDateTime,
		FinalResolutionDateTime: dbMarket.FinalResolutionDateTime,
		ResolutionResult:        dbMarket.ResolutionResult,
		CreatorUsername:         dbMarket.CreatorUsername,
		YesLabel:                dbMarket.YesLabel,
		NoLabel:                 dbMarket.NoLabel,
		Status:                  status,
		CreatedAt:               dbMarket.CreatedAt,
		UpdatedAt:               dbMarket.UpdatedAt,
		InitialProbability:      dbMarket.InitialProbability,
		UTCOffset:               dbMarket.UTCOffset,
	}
}

package bets

import (
	"context"
	"time"

	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/models"
	"socialpredict/setup"
)

// Repository exposes the persistence layer needed by the bets domain service.
type BetWriter interface {
	Create(ctx context.Context, bet *models.Bet) error
}

// BetHistoryReader exposes prior-participation lookups used for buy fee rules.
type BetHistoryReader interface {
	UserHasBet(ctx context.Context, marketID uint, username string) (bool, error)
}

// Repository exposes the persistence layer needed by the bets domain service.
type Repository interface {
	BetWriter
	BetHistoryReader
}

// MarketService exposes the subset of market operations required by bets.
type MarketReader interface {
	GetMarket(ctx context.Context, id int64) (*dmarkets.Market, error)
}

// PositionReader exposes the position reads needed by share-sale flows.
type PositionReader interface {
	GetUserPositionInMarket(ctx context.Context, marketID int64, username string) (*dmarkets.UserPosition, error)
}

// MarketService exposes the subset of market operations required by bets.
type MarketService interface {
	MarketReader
	PositionReader
}

// MarketGate ensures market openness before betting operations.
type MarketGate interface {
	Open(ctx context.Context, marketID int64) (*dmarkets.Market, error)
}

// UserService exposes the subset of user operations required by bets.
type UserReader interface {
	GetUser(ctx context.Context, username string) (*dusers.User, error)
}

// TransactionRecorder exposes account mutations used by the betting ledger.
type TransactionRecorder interface {
	ApplyTransaction(ctx context.Context, username string, amount int64, transactionType string) error
}

// UserService exposes the subset of user operations required by bets.
type UserService interface {
	UserReader
	TransactionRecorder
}

// PlaceValidator allows validation rules to be extended without changing the service.
type PlaceValidator interface {
	Validate(ctx context.Context, req PlaceRequest) (string, error)
}

// SellValidator allows sell validation rules to be extended without changing the service.
type SellValidator interface {
	Validate(ctx context.Context, req SellRequest) (string, error)
}

// SaleCalculator encapsulates sale pricing and dust rules.
type SaleCalculator interface {
	Calculate(pos *dmarkets.UserPosition, sharesOwned int64, creditsRequested int64) (SaleQuote, error)
}

// FeeCalculator encapsulates buy fee calculations.
type FeeCalculator interface {
	Calculate(hasBet bool, amount int64) betFees
}

// BalanceGuard validates user balances against debt limits.
type BalanceGuard interface {
	EnsureSufficient(balance, totalCost int64) error
}

// BetLedger encapsulates persistence and user accounting for bets.
type BetLedger interface {
	ChargeAndRecord(ctx context.Context, bet *models.Bet, totalCost int64) error
	CreditSale(ctx context.Context, bet *models.Bet, saleValue int64) error
}

// Clock allows time to be mocked in tests.
type Clock interface {
	Now() time.Time
}

type serviceClock struct{}

func (serviceClock) Now() time.Time { return time.Now() }

// ServiceInterface defines the behaviour offered by the bets domain.
type ServiceInterface interface {
	Place(ctx context.Context, req PlaceRequest) (*PlacedBet, error)
	Sell(ctx context.Context, req SellRequest) (*SellResult, error)
}

// Service implements the bets domain logic.
type Service struct {
	repo    Repository
	markets MarketService
	users   UserService
