type reverseBetSorter struct{}

func (reverseBetSorter) Sort(bets []boundary.Bet) []boundary.Bet {
	sorted := make([]boundary.Bet, len(bets))
	copy(sorted, bets)
	for i, j := 0, len(sorted)-1; i < j; i, j = i+1, j-1 {
		sorted[i], sorted[j] = sorted[j], sorted[i]
	}
	return sorted
}

